sql:
SELECT AVG(loan_amnt) AS average_loan_amount
FROM loans
WHERE emp_length = '10+ years' AND loan_status = 'Fully Paid';

SELECT loan_id
FROM loans
ORDER BY total_paid DESC, loan_id;

external_knowledge:
- 'broken the bank' refers to borrowers who have made a total payment amount greater than 10,000;
- 'freed themselves' from debt refers to borrowers who have an outstanding balance less than 5,000;
- 'big-ticket borrowing' refers to borrowers who have an average loan amount greater than 15,000.
